            "blockType": "Code",
            "content": [
                {
                    "contentType": "Text",
                    "content": "const newBlock: BlockModel = {\nid: 'new-block', \nblockType: 'Paragraph',\ncontent: [ { \ncontentType: 'Text', content: 'This is a newly added block'}]\n};\neditor.addBlock(newBlock,'target-block-id');\nconst blockData = editor.getDataAsJson('new-block');"
                }
            ]
        },
        {
            "blockType": "Paragraph"
        }
    ],
