                                        "bold": true,
                                        "color": "#047857"
                                    }
                                }
                            },
                            {
                                "contentType": "Text",
                                "content": "Use events wisely — avoid unnecessary listeners to maintain optimal performance."
                            }
                        ]
                    }
                ]
            }
        },
        {
            "blockType": "Heading",
            "properties": {
                "level": 3
            },
            "content": [
                {
                    "contentType": "Text",
                    "content": "Core events"
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "blockChanged: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Detect when blocks are added, removed, transformed or updated."
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "focus: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Track active blocks when the editor gains focus."
                }
            ]
        },
        {
            "blockType": "Heading",
            "properties": {
                "level": 4
            },
            "content": [
                {
                    "contentType": "Text",
                    "content": "Basic usage"
                }
            ]
        },
        {
            "blockType": "Code",
            "content": [
                {
                    "contentType": "Text",
                    "content": "focus: (args: FocusEventArgs) => { \n// Custom actions when the editor gains focus\n} \nblockChanged: (args: BlockChangedEventArgs) {\n //Custom actions on a block are added, removed, transformed, or updated. \n}\n"
                }
            ]
        },
        {
            "blockType": "Heading",
            "properties": {
                "level": 3
            },
            "content": [
                {
                    "contentType": "Text",
                    "content": "Event usage in the Block Editor"
