        },
        {
            "blockType": "Paragraph",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Events are commonly used for:"
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Autosave: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Trigger blockChanged to save content periodically."
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Collaboration: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Sync changes in real-time using blockChanged."
                }
            ]
        },
        {
            "blockType": "Heading",
            "properties": {
                "level": 3
            },
            "content": [
                {
                    "contentType": "Text",
                    "content": "Cases to avoid when binding events"
                }
            ]
        },
        {
            "blockType": "NumberedList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "High-frequency events without throttling Example: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Binding heavy logic to blockChanged without debouncing can cause performance issues."
                }
            ]
        },
        {
            "blockType": "NumberedList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Duplicate listeners: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Adding multiple listeners for the same event can lead to memory leaks and unexpected behavior."
                }
            ]
        },
        {
            "blockType": "NumberedList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Unnecessary global listeners: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Avoid binding events that are not relevant to your workflow."
                }
            ]
        },
        {
            "blockType": "NumberedList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Complex operations inside event callbacks: ",
                    "properties": {
                        "styles": {
                            "bold": true
                        }
                    }
                },
                {
                    "contentType": "Text",
                    "content": "Heavy DOM manipulation or API calls inside frequent events can degrade the user experience."
                }
            ]
        },
        {
            "blockType": "Heading",
            "properties": {
                "level": 3
            },
            "content": [
                {
                    "contentType": "Text",
                    "content": "Best practices"
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Use debouncing for frequent events like blockChanged."
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Remove listeners when they are no longer needed."
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Keep event callbacks lightweight and efficient."
                }
            ]
        },
        {
            "blockType": "BulletList",
            "content": [
                {
                    "contentType": "Text",
                    "content": "Combine events for analytics without impacting UX."
                }
            ]
        },
        {
            "blockType": "Quote",
            "content": [
                {
                    "contentType": "Text",
                    "content": "“Every interaction tells a story — listen carefully.”",
                    "properties": {
                        "styles": {
                            "italic": true
                        }
                    }
                }
            ]
        },
        {
            "blockType": "Paragraph"
        }
